CustomField.formula:
IF(
    ISPICKVAL(Factor_PriceExponentialMin__c,"TC以上"),1.0,
    IF(
        ISPICKVAL(Factor_PriceExponentialMin__c, "WC以上TC未満"),
        IF(
            ISBLANK(TEXT(Factor_PriceExponential_Manual2Min__c)),0.8,VALUE(TEXT(Factor_PriceExponential_Manual2Min__c))
        ),
        IF(
            ISPICKVAL(Factor_PriceExponentialMin__c, "WC未満"),
            IF(
                ISBLANK(TEXT(Factor_PriceExponential_ManualMin__c )),0.6,VALUE(TEXT(Factor_PriceExponential_ManualMin__c ))
            ),0
        )
    )
)
